import{_ as o,o as c,c as i,ag as h}from"./chunks/framework.DTiDeF2Q.js";const u=JSON.parse('{"title":"Bí Danh Chmod | Dotfiles (VI)","titleTemplate":":title","description":"Lệnh quyền truy cập rút gọn. Tổng quan cho Dotfiles v0.2.495. Tương thích với macOS, Linux và WSL qua Dotfiles.","frontmatter":{"title":"Bí Danh Chmod | Dotfiles","description":"Lệnh quyền truy cập rút gọn. Tổng quan cho Dotfiles v0.2.495. Tương thích với macOS, Linux và WSL qua Dotfiles.","lang":"vi-VN","author":"Sebastien Rousseau","lastUpdated":true,"image":"/logo.png","imageAlt":"Bí Danh Chmod | Dotfiles preview","canonical":"/vi/aliases/chmod/","robots":"index, follow","draft":false,"noindex":false,"sitemap":true,"breadcrumbTitle":"Bí danh Chmod","pageType":"docs","schemaType":"WebPage","permalink":"/vi/aliases/chmod/"},"headers":[],"relativePath":"vi/aliases/chmod/index.md","filePath":"vi/aliases/chmod/index.md","lastUpdated":1773010926000}'),n={name:"vi/aliases/chmod/index.md"};function a(d,e,t,l,s,r){return c(),i("div",null,[...e[0]||(e[0]=[h('<h1 id="bi-danh-chmod" tabindex="-1">Bí Danh Chmod <a class="header-anchor" href="#bi-danh-chmod" aria-label="Permalink to &quot;Bí Danh Chmod&quot;">​</a></h1><p>Lệnh quyền truy cập rút gọn.</p><p>Trang này giới thiệu một nhóm bí danh và các phím tắt lệnh thường dùng. Đọc trang này trước để hiểu quy ước đặt tên, đầu vào mong đợi và mẫu thực thi an toàn. Sau đó mở phụ lục tham khảo để xem toàn bộ danh sách lệnh và cú pháp chính xác. Các bí danh này giảm việc gõ lặp lại và duy trì hành vi quy trình làm việc nhất quán trên macOS, Linux và WSL.</p><h2 id="khi-nao-su-dung" tabindex="-1">Khi Nào Sử Dụng <a class="header-anchor" href="#khi-nao-su-dung" aria-label="Permalink to &quot;Khi Nào Sử Dụng&quot;">​</a></h2><p>Sử dụng trang này trước công việc shell hàng ngày khi bạn cần mẫu lệnh dự đoán được.</p><h2 id="bao-gom" tabindex="-1">Bao Gồm <a class="header-anchor" href="#bao-gom" aria-label="Permalink to &quot;Bao Gồm&quot;">​</a></h2><ul><li>Bí danh: 17</li><li>Hàm hỗ trợ: 0</li><li>Tệp nguồn: 1</li></ul><h2 id="vi-du-nhanh" tabindex="-1">Ví Dụ Nhanh <a class="header-anchor" href="#vi-du-nhanh" aria-label="Permalink to &quot;Ví Dụ Nhanh&quot;">​</a></h2><ul><li><code>chmod_000</code> → <code>change_permission 000</code></li><li><code>chmod_1755</code> → <code>&#39;change_permission 1755&#39; # Sticky bit + 755</code></li><li><code>chmod_2755</code> → <code>&#39;change_permission 2755&#39; # Setgid + 755</code></li><li><code>chmod_400</code> → <code>&#39;change_permission 400&#39; # Chỉ đọc cho chủ sở hữu</code></li><li><code>chmod_444</code> → <code>&#39;change_permission 444&#39; # Chỉ đọc cho tất cả</code></li><li><code>chmod_4755</code> → <code>&#39;change_permission 4755&#39; # Setuid + 755</code></li><li><code>chmod_600</code> → <code>&#39;change_permission 600&#39; # Đọc/ghi cho chủ sở hữu</code></li><li><code>chmod_644</code> → <code>&#39;change_permission 644&#39; # Đọc/ghi chủ sở hữu, đọc cho người khác</code></li><li><code>chmod_664</code> → <code>&#39;change_permission 664&#39; # Đọc/ghi chủ sở hữu và nhóm, đọc cho người khác</code></li><li><code>chmod_666</code> → <code>&#39;change_permission 666&#39; # Đọc/ghi cho tất cả</code></li><li><code>chmod_700</code> → <code>&#39;change_permission 700&#39; # Toàn quyền chỉ chủ sở hữu</code></li><li><code>chmod_744</code> → <code>&#39;change_permission 744&#39; # Toàn quyền chủ sở hữu, đọc cho người khác</code></li></ul><h2 id="buoc-tiep-theo" tabindex="-1">Bước Tiếp Theo <a class="header-anchor" href="#buoc-tiep-theo" aria-label="Permalink to &quot;Bước Tiếp Theo&quot;">​</a></h2><p>Mở danh sách đầy đủ:</p>',11)])])}const g=o(n,[["render",a]]);export{u as __pageData,g as default};
